  <script type="text/babel">
    function parsePDF(arrayBuffer) {
      try {
        const bytes = new Uint8Array(arrayBuffer);
        let raw = "";
        for (let i = 0; i < bytes.length; i++) {
          raw += String.fromCharCode(bytes[i]);
        }

        const lines = [];

        // Extract text from stream objects
        const streamRegex = /stream\r?\n([\s\S]*?)\r?\nendstream/g;
        let match;
        while ((match = streamRegex.exec(raw)) !== null) {
          const content = match[1];
          // Extract text from BT...ET blocks
          const btRegex = /BT([\s\S]*?)ET/g;
          let btMatch;
          while ((btMatch = btRegex.exec(content)) !== null) {
            const block = btMatch[1];
            // Extract Tj and TJ strings
            const tjRegex = /\(([^)]*)\)\s*Tj/g;
            let tjMatch;
            while ((tjMatch = tjRegex.exec(block)) !== null) {
              let text = tjMatch[1];
              // Unescape PDF string escapes
              text = text.replace(/\\n/g, '\n').replace(/\\r/g, '\r').replace(/\\t/g, '\t');
              text = text.replace(/\\\(/g, '(').replace(/\\\)/g, ')').replace(/\\\\/g, '\\');
              lines.push(text);
            }
            // TJ arrays
            const tjArrayRegex = /\[([^\]]*)\]\s*TJ/g;
            let tjArrMatch;
            while ((tjArrMatch = tjArrayRegex.exec(block)) !== null) {
              const arr = tjArrMatch[1];
              const strRegex = /\(([^)]*)\)/g;
              let strMatch;
              let combined = "";
              while ((strMatch = strRegex.exec(arr)) !== null) {
                let text = strMatch[1];
                text = text.replace(/\\n/g, '\n').replace(/\\r/g, '\r').replace(/\\t/g, '\t');
                text = text.replace(/\\\(/g, '(').replace(/\\\)/g, ')').replace(/\\\\/g, '\\');
                combined += text;
              }
              if (combined) lines.push(combined);
            }
          }
        }

        return lines.join('\n');
      } catch (e) {
        console.error('PDF parse error:', e);
        return '';
      }
    }

    function analyzeText(text, fileType) {
      // Citation counting: bracket style [1], [42], etc.
      const citationMatches = text.match(/\[\d+\]/g);
      const citations = citationMatches ? citationMatches.length : 0;

      // Word counting using the specified regex
      const wordMatches = text.match(/\b[\w'-]+\b/g);
      const totalWords = wordMatches ? wordMatches.length : 0;

      // Keyword density
      const lowerText = text.toLowerCase();
      const lowerWords = wordMatches ? wordMatches.map(w => w.toLowerCase()) : [];

      const quantumCount = lowerWords.filter(w => w === 'quantum').length;
      const entanglementCount = lowerWords.filter(w => w === 'entanglement').length;

      const quantumDensity = totalWords > 0 ? Math.round((quantumCount / totalWords) * 1000) / 1000 : 0;
      const entanglementDensity = totalWords > 0 ? Math.round((entanglementCount / totalWords) * 1000) / 1000 : 0;

      // Section summaries
      const sectionSummaries = extractSections(text, fileType);

      return {
        fileType,
        citations,
        totalWords,
        keywordDensity: {
          quantum: { count: quantumCount, density: quantumDensity },
          entanglement: { count: entanglementCount, density: entanglementDensity }
        },
        sectionSummaries
      };
    }

    function extractSections(text, fileType) {
      const lines = text.split('\n');
      const sections = [];
      let currentTitle = null;
      let currentBody = [];

      for (const line of lines) {
        const trimmed = line.trim();
        // Detect headings: lines starting with #
        const headingMatch = trimmed.match(/^(#{1,6})\s+(.+)/);
        if (headingMatch) {
          // Save previous section
          if (currentTitle !== null) {
            sections.push({
              title: currentTitle,
              summary: getFirstSentence(currentBody.join(' '))
            });
          }
          currentTitle = headingMatch[2].trim();
          currentBody = [];
        } else if (currentTitle !== null) {
          if (trimmed.length > 0) {
            currentBody.push(trimmed);
          }
        }
      }

      // Don't forget last section
      if (currentTitle !== null) {
        sections.push({
          title: currentTitle,
          summary: getFirstSentence(currentBody.join(' '))
        });
      }

      // For PDF without markdown headings, try to detect headings heuristically
      if (sections.length === 0 && fileType === 'pdf') {
        // Try uppercase or short lines as headings
        let currentT = null;
        let currentB = [];
        for (const line of lines) {
          const trimmed = line.trim();
          if (trimmed.length === 0) continue;
          // Heuristic: short lines (< 60 chars) that don't end with period could be headings
          if (trimmed.length < 60 && !trimmed.endsWith('.') && !trimmed.endsWith(',') && trimmed.length > 0) {
            if (currentT !== null) {
              sections.push({
                title: currentT,
                summary: getFirstSentence(currentB.join(' '))
              });
            }
            currentT = trimmed;
            currentB = [];
          } else if (currentT !== null) {
            currentB.push(trimmed);
          }
        }
        if (currentT !== null) {
          sections.push({
            title: currentT,
            summary: getFirstSentence(currentB.join(' '))
          });
        }
      }

      return sections;
    }

    function getFirstSentence(text) {
      if (!text || text.trim().length === 0) return '';
      // Match first sentence ending with . ! or ?
      const match = text.match(/^(.*?[.!?])(?:\s|$)/);
      if (match) return match[1].trim();
      return text.trim();
    }

    function App() {
      const [analysis, setAnalysis] = React.useState(null);
      const [status, setStatus] = React.useState('Please upload a journal file (.md, .markdown, or .pdf)');
      const [statusType, setStatusType] = React.useState('info');

      const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        setStatus(`Analyzing "${file.name}"...`);
        setStatusType('info');

        const ext = file.name.split('.').pop().toLowerCase();
        const fileType = ext === 'pdf' ? 'pdf' : 'markdown';

        if (fileType === 'pdf') {
          const reader = new FileReader();
          reader.onload = (ev) => {
            const text = parsePDF(ev.target.result);
            const result = analyzeText(text, 'pdf');
            setAnalysis(result);
            setStatus(`Analysis complete for "${file.name}"`);
            setStatusType('success');
          };
          reader.readAsArrayBuffer(file);
        } else {
          const reader = new FileReader();
          reader.onload = (ev) => {
            const text = ev.target.result;
            const result = analyzeText(text, 'markdown');
            setAnalysis(result);
            setStatus(`Analysis complete for "${file.name}"`);
            setStatusType('success');
          };
          reader.readAsText(file);
        }
      };

      const defaultAnalysis = {
        fileType: "",
        citations: 0,
        totalWords: 0,
        keywordDensity: {
          quantum: { count: 0, density: 0 },
          entanglement: { count: 0, density: 0 }
        },
        sectionSummaries: []
      };

      const data = analysis || defaultAnalysis;

      return (
        <div>
          <h1>Journal Analyzer</h1>

          <div className="upload-section">
            <h2>Upload Journal</h2>
            <input
              type="file"
              accept=".md,.markdown,.pdf"
              onChange={handleFileChange}
            />
            <div className={`status ${statusType}`}>{status}</div>
          </div>

          {analysis && (
            <>
              <div className="dashboard-section">
                <h2>Citation Frequency</h2>
                <table>
                  <thead>
                    <tr><th>Metric</th><th>Value</th></tr>
                  </thead>
                  <tbody>
                    <tr><td>Total Citations</td><td>{data.citations}</td></tr>
                  </tbody>
                </table>
              </div>

              <div className="dashboard-section">
                <h2>Keyword Density</h2>
                <table>
                  <thead>
                    <tr><th>Keyword</th><th>Count</th><th>Density</th></tr>
                  </thead>
                  <tbody>
                    <tr>
                      <td>quantum</td>
                      <td>{data.keywordDensity.quantum.count}</td>
                      <td>{data.keywordDensity.quantum.density}</td>
                    </tr>
                    <tr>
                      <td>entanglement</td>
                      <td>{data.keywordDensity.entanglement.count}</td>
                      <td>{data.keywordDensity.entanglement.density}</td>
                    </tr>
                  </tbody>
                </table>
              </div>

              <div className="dashboard-section">
                <h2>Section Summaries</h2>
                <div className="sections">
                  <ul>
                    {data.sectionSummaries.map((sec, i) => (
                      <li key={i}>
                        <strong>{sec.title}</strong>
                        <span>{sec.summary}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </>
          )}

          <pre id="analysis-output">{JSON.stringify(data, null, 2)}</pre>
        </div>
      );
    }

    const root = ReactDOM.createRoot(document.getElementById('root'));
    root.render(<App />);
  </script>
</body>
</html>
